import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.widget.Button
import android.widget.EditText
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import java.util.concurrent.Executor

class LoginActivity : AppCompatActivity() {

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_AUTHENTICATED = "authenticated"
        private const val KEY_PASSWORD = "password"
    }

    private lateinit var prefs: SharedPreferences
    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo
    private lateinit var executor: Executor

    private lateinit var passwordField: EditText
    private lateinit var loginButton: Button
    private lateinit var biometricButton: Button

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        if (prefs.getBoolean(KEY_AUTHENTICATED, false)) {
            goToHome()
            return
        }

        setContentView(R.layout.activity_login)

        passwordField = findViewById(R.id.passwordField)
        loginButton = findViewById(R.id.loginButton)
        biometricButton = findViewById(R.id.biometricButton)

        executor = ContextCompat.getMainExecutor(this)

        setupBiometricPrompt()
        setupUi()
        updateBiometricAvailability()
    }

    private fun setupUi() {
        loginButton.setOnClickListener {
            val password = passwordField.text?.toString().orEmpty()
            if (isPasswordValid(password)) {
                prefs.edit().putBoolean(KEY_AUTHENTICATED, true).apply()
                goToHome()
            } else {
                Toast.makeText(this, "Incorrect password", Toast.LENGTH_SHORT).show()
            }
        }

        biometricButton.setOnClickListener {
            showBiometricPrompt()
        }
    }

    private fun setupBiometricPrompt() {
        biometricPrompt = BiometricPrompt(this, executor, object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                Toast.makeText(this@LoginActivity, "Biometric error: $errString", Toast.LENGTH_SHORT).show()
                showPasswordFallback()
            }

            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                prefs.edit().putBoolean(KEY_AUTHENTICATED, true).apply()
                Toast.makeText(this@LoginActivity, "Authentication successful", Toast.LENGTH_SHORT).show()
                goToHome()
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                Toast.makeText(this@LoginActivity, "Fingerprint not recognized. Use password.", Toast.LENGTH_SHORT).show()
                showPasswordFallback()
            }
        })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Sign in with fingerprint")
            .setSubtitle("Use your fingerprint to continue")
            .setDescription("Place your finger on the sensor")
            .setNegativeButtonText("Use password")
            .build()
    }

    private fun updateBiometricAvailability() {
        val biometricManager = BiometricManager.from(this)
        val canAuthenticate = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG)

        biometricButton.isEnabled = canAuthenticate == BiometricManager.BIOMETRIC_SUCCESS
        biometricButton.text = if (biometricButton.isEnabled) "Use Fingerprint" else "Fingerprint Unavailable"
    }

    private fun showBiometricPrompt() {
        biometricPrompt.authenticate(promptInfo)
    }

    private fun showPasswordFallback() {
        passwordField.requestFocus()
        Toast.makeText(this, "Please enter your password to continue", Toast.LENGTH_SHORT).show()
    }

    private fun isPasswordValid(password: String): Boolean {
        val savedPassword = prefs.getString(KEY_PASSWORD, "") ?: ""
        return password.isNotBlank() && (savedPassword.isBlank() || password == savedPassword)
    }

    private fun goToHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }
}

class HomeActivity : AppCompatActivity() {

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_AUTHENTICATED = "authenticated"
    }

    private lateinit var prefs: SharedPreferences

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        if (!prefs.getBoolean(KEY_AUTHENTICATED, false)) {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
            return
        }

        setContentView(R.layout.activity_home)
    }

    override fun onResume() {
        super.onResume()
        if (!prefs.getBoolean(KEY_AUTHENTICATED, false)) {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}